+
+func validSpanID(value string) bool {
+	return validHex(value, 16) && !allZero(value)
+}
+
+func validHex(value string, length int) bool {
+	if len(value) != length {
+		return false
+	}
+
+	for _, r := range value {
+		switch {
+		case r >= '0' && r <= '9':
+		case r >= 'a' && r <= 'f':
+		case r >= 'A' && r <= 'F':
+		default:
+			return false
+		}
+	}
+
+	return true
+}
+
+func allZero(value string) bool {
+	for _, r := range value {
+		if r != '0' {
+			return false
+		}
+	}
+
+	return true
